package jetbrains.mps.samples.fincalculator.support.runtime;

/*Generated by MPS */

import javax.swing.JFrame;
import javax.swing.JPanel;
import java.awt.GridLayout;
import java.awt.BorderLayout;
import javax.swing.JComponent;
import javax.swing.JLabel;
import javax.swing.BorderFactory;

public class CalculationFrame extends JFrame {
  private JPanel smallPanel = new JPanel();
  private JPanel bigPanel = new JPanel();

  public CalculationFrame() {
    smallPanel.setLayout(new GridLayout(0, 3));
    bigPanel.setLayout(new GridLayout(0, 1));
    this.setLayout(new BorderLayout());
    add(smallPanel, BorderLayout.NORTH);
    add(bigPanel, BorderLayout.CENTER);
  }

  protected void addToSmallPanel(String prefix, JComponent component, String postFix) {
    smallPanel.add(new JLabel(prefix));
    smallPanel.add(component);
    smallPanel.add(new JLabel(postFix));
  }

  protected void addToBigPanel(String title, JComponent component) {
    JPanel panel = new JPanel();
    component.setBorder(BorderFactory.createTitledBorder(title));
    panel.add(component);
    bigPanel.add(panel);
  }
}
